// Adzuna doesn't handle long OR queries well, so we run multiple searches
const queries = [
  'machine learning',
  'computer vision',
  'deep learning',
  'software engineer',
  '3D engineer',
  'rendering engineer',
  'python developer'
];

const appId = $env.ADZUNA_APP_ID;
const appKey = $env.ADZUNA_KEY;
const allResults = [];

for (const q of queries) {
  try {
    const url = `https://api.adzuna.com/v1/api/jobs/fr/search/1?app_id=${appId}&app_key=${appKey}&results_per_page=20&what=${encodeURIComponent(q)}&where=France&max_days_old=3&content-type=application/json`;
    const response = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (response.results) {
      allResults.push(...response.results);
    }
  } catch(e) {
    // Skip failed queries
  }
}

return [{ json: { results: allResults, count: allResults.length, __CLASS__: 'Adzuna::API::Response::JobSearchResults' } }];

// SerpAPI Google Jobs requires hl=fr&gl=fr for French results
// Run multiple queries to maximize coverage (free tier: 100 searches/month)
const queries = [
  'computer vision engineer',
  'machine learning engineer',
  'software engineer python',
  'ingenieur deep learning'
];

const apiKey = $env.SERPAPI_KEY;
const allJobs = [];

for (const q of queries) {
  try {
    const url = `https://serpapi.com/search.json?engine=google_jobs&q=${encodeURIComponent(q)}&location=Paris,+France&hl=fr&gl=fr&chips=date_posted:3days&api_key=${apiKey}`;
    const response = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (response.jobs_results) {
      allJobs.push(...response.jobs_results);
    }
  } catch(e) {
    // Skip failed queries
  }
}

return [{ json: { jobs_results: allJobs, count: allJobs.length } }];

// Normalize jobs from all 6 sources into a common format
let adzunaItems = [];
try { adzunaItems = $('Adzuna Job Search').first().json.results || []; } catch(e) {}
let serpItems = [];
try { serpItems = $('Google Jobs via SerpAPI').first().json.jobs_results || []; } catch(e) {}
let ftItems = [];
try { ftItems = $('France Travail').first().json.results || []; } catch(e) {}
let remotiveItems = [];
try { remotiveItems = $('Remotive').first().json.jobs || []; } catch(e) {}
let arbeitnowItems = [];
try { arbeitnowItems = $('Arbeitnow').first().json.data || []; } catch(e) {}
let jsearchItems = [];
try { jsearchItems = $('JSearch').first().json.data || []; } catch(e) {}

const jobs = [];
const seen = new Set();

function dedupKey(title, company) {
  return `${(title || '').toLowerCase().trim()}|${(company || '').toLowerCase().trim()}`;
}

// Adzuna
for (const job of adzunaItems) {
  const key = dedupKey(job.title, job.company?.display_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company?.display_name || '',
    location: job.location?.display_name || '',
    description: job.description || '',
    url: job.redirect_url || '',
    salary_min: job.salary_min || null,
    salary_max: job.salary_max || null,
    source: 'Adzuna',
    date_posted: job.created || '',
  });
}

// Google Jobs (SerpAPI)
for (const job of serpItems) {
  const key = dedupKey(job.title, job.company_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company_name || '',
    location: job.location || '',
    description: job.description || '',
    url: job.apply_options?.[0]?.link || job.share_link || '',
    salary_min: null,
    salary_max: null,
    salary_text: job.detected_extensions?.salary || null,
    source: 'Google Jobs',
    date_posted: job.detected_extensions?.posted_at || '',
  });
}

// France Travail
for (const job of ftItems) {
  const key = dedupKey(job.intitule, job.entreprise?.nom);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.intitule || '',
    company: job.entreprise?.nom || '',
    location: job.lieuTravail?.libelle || '',
    description: job.description || '',
    url: job.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${job.id}`,
    salary_min: null,
    salary_max: null,
    salary_text: job.salaire?.libelle || null,
    source: 'France Travail',
    date_posted: job.dateCreation || '',
  });
}

// Remotive
for (const job of remotiveItems) {
  const key = dedupKey(job.title, job.company_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company_name || '',
    location: job.candidate_required_location || 'Remote',
    description: job.description || '',
    url: job.url || '',
    salary_min: null,
    salary_max: null,
    salary_text: job.salary || null,
    source: 'Remotive',
    date_posted: job.publication_date || '',
  });
}

// Arbeitnow
for (const job of arbeitnowItems) {
  const key = dedupKey(job.title, job.company_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.title || '',
    company: job.company_name || '',
    location: job.location || (job.remote ? 'Remote' : ''),
    description: job.description || '',
    url: job.url || `https://www.arbeitnow.com/view/${job.slug}`,
    salary_min: null,
    salary_max: null,
    source: 'Arbeitnow',
    date_posted: job.created_at ? new Date(job.created_at * 1000).toISOString() : '',
  });
}

// JSearch (LinkedIn, Indeed, Glassdoor aggregated)
for (const job of jsearchItems) {
  const key = dedupKey(job.job_title, job.employer_name);
  if (seen.has(key)) continue;
  seen.add(key);
  jobs.push({
    title: job.job_title || '',
    company: job.employer_name || '',
    location: [job.job_city, job.job_state, job.job_country].filter(Boolean).join(', '),
    description: job.job_description || '',
    url: job.job_apply_link || '',
    salary_min: job.job_min_salary || null,
    salary_max: job.job_max_salary || null,
    source: 'JSearch',
    date_posted: job.job_posted_at_datetime_utc || '',
  });
}

console.log(`[Normalize] Adzuna(${adzunaItems.length}) SerpAPI(${serpItems.length}) FranceTravail(${ftItems.length}) Remotive(${remotiveItems.length}) Arbeitnow(${arbeitnowItems.length}) JSearch(${jsearchItems.length}) => ${jobs.length} unique`);

return jobs.map(j => ({ json: j }));

// Filter out already-processed jobs + deduplicate within batch
const MAX_PER_RUN = 15;

// Build dedup set from existing sheet rows
const existingKeys = new Set();
let sheetRowCount = 0;

try {
  const sheetItems = $('Read Existing Jobs').all();
  sheetRowCount = sheetItems.length;
  for (const item of sheetItems) {
    const d = item.json;
    if (!d || Object.keys(d).length === 0) continue;
    const role = String(d['Role'] || d['role'] || '').toLowerCase().trim();
    const company = String(d['Company'] || d['company'] || '').toLowerCase().trim();
    const location = String(d['Location'] || d['location'] || '').toLowerCase().trim();
    if (role || company) existingKeys.add(`${role}|${company}|${location}`);
  }
} catch(e) {
  console.log('[Filter] WARNING: Could not read existing jobs: ' + e.message);
}

const allNormalized = $('Normalize & Deduplicate').all();

// Deduplicate WITHIN this batch (Normalize may run multiple times due to n8n
// executing once per source connection — this removes the duplicates)
const batchSeen = new Set();
const newJobs = allNormalized.filter(item => {
  const j = item.json;
  const key = `${(j.title || '').toLowerCase().trim()}|${(j.company || '').toLowerCase().trim()}|${(j.location || '').toLowerCase().trim()}`;

  // Skip duplicates within this batch
  if (batchSeen.has(key)) return false;
  batchSeen.add(key);

  // Skip if already in sheet
  if (existingKeys.has(key)) return false;
  return true;
});

console.log(`[Filter] Input: ${allNormalized.length} (with dupes) | Unique: ${batchSeen.size} | In sheet: ${existingKeys.size} | New: ${newJobs.length} (max ${MAX_PER_RUN})`);

if (newJobs.length === 0) return [];
return newJobs.slice(0, MAX_PER_RUN);

// ── Groq tailoring (30 RPM, 1000 RPD, 100K TPD free tier) ───────────────────
const items = $input.all();
const apiKey = $env.GROQ_API_KEY;
const MODEL = 'llama-3.3-70b-versatile';

async function tailorJob(item) {
  const job = item.json;
  const systemPrompt = 'You are a resume tailoring assistant. You always respond with valid JSON only, no markdown.';
  const userPrompt = `Given a job posting and a candidate resume, produce a tailored version that reorders and reweights content to match the job.

JOB POSTING:
Title: ${job.title}
Company: ${job.company}
Description: ${(job.description || '').substring(0, 2000)}
Identify and incorporate relevant ATS keywords from the job description.

CANDIDATE EXPERIENCE (pick 2-3, reorder by relevance, expand into 3-4 polished bullets each):

1. Computer Vision R&D Engineer | GoPro | Paris | Mar 2025 -- Sep 2025
   Sim-to-Real DL pipeline for 360 stitching parallax fix; procedural synthetic dataset generation in Blender Python API; custom PyTorch model beating production baseline; >50% processing time reduction

2. Chief Technical Officer | BargMe Startup | Remote | Jan 2023 -- Nov 2024
   Led multidisciplinary team building Sawem web/mobile shopping assistant; barcode recognition via smartphone camera; AI-based recommendation engine (Python, Scikit-learn, Pandas); deployed on Debian VPS; cross-platform mobile via React Native

3. Data Management & Software Optimization Intern | Caisse d'Epargne IDF | Paris | Aug 2024 -- Sep 2024
   Performance testing and flaw detection for internal banking software; client data sheet management; data organization and reporting improvements

4. Technical Content Creator (3D & AI) | SkillDino (InspirationTuts) | Remote | Jan 2022 -- Dec 2023
   Educational content on 3D modeling, VFX, AI trends for 300K+ subscribers; tutorials on CV techniques (object tracking, AR) in Blender/Unity/OpenCV workflows

5. Full Stack & Automation Engineer | ENTMV | Algiers | Feb 2022 -- Jun 2022
   Web app for document management automation; digitization of admin documents; MERN Stack (MongoDB, Express.js, React.js, Node.js)

PROJECTS (pick 2-3, reorder by relevance, expand into 2-3 polished bullets each):

1. Automated Job Search Pipeline | n8n, MCP, Agentic AI, Python, Docker | 2025
   Built end-to-end agentic automation: scrapes 6 job APIs, LLM-tailors resume per job, compiles LaTeX PDF, uploads to Drive, logs to Sheets, sends email digest; self-hosted n8n with MCP server integration

2. Mistral Msg: LLM Messaging App | Next.js, TypeScript, Mistral AI API | Nov 2024
   Real-time messaging with AI context-based reply suggestions and prompt-based rewriting; LLM API integration in production web app

3. License Plate Detection in Dusty Env | YOLOv8, EasyOCR, Data Augmentation | May 2024
   YOLOv8 detection + EasyOCR recognition in harsh conditions; data augmentation (flip, crop, rotate, blur); benchmarked HOG+SVM vs deep learning

4. 3D Reconstruction with Stereo Vision | OpenCV, SIFT, Triangulation | May 2023
   Stereo vision system: camera calibration, SIFT matching, triangulation to 3D point clouds; Matplotlib visualization

5. DeOldify: AI Image Colorization | PyTorch, GANs, FastAI | Jan 2023
   GAN-based grayscale colorization for manga and historical photos; PyTorch + FastAI training; preprocessing for edge sharpness

6. ASYEL: Sign Language Translation | LSTM, Time-Series, Pose Estimation | Apr 2022
   Gesture-to-speech pipeline with LSTM sequence classification; custom recorded dataset; Won 2nd Prize National Innovation Competition

7. Autonomous Safety & Fall Detection | Pose Estimation, Edge AI | Nov 2021
   AI safety module using Skeleton Tracking for incident detection; human-in-the-loop OK gesture verification; 1st Prize Google DevFest Hackathon

8. Real-Time Driver Monitoring (ADAS) | MediaPipe 3D, OpenCV | Sep 2021
   Drowsiness/distraction detection via 3D Facial Mesh (468 landmarks); EAR and yawning analysis; Samsung Judges Favorite

SKILLS (reorder by relevance, omit irrelevant categories):
- Computer Vision & 3D: OpenCV, MediaPipe, YOLO/YOLOv8, EasyOCR, Optical Flow, Stereo Vision, Multi-view Geometry, Depth Estimation, SIFT
- Deep Learning: PyTorch, TensorFlow, FastAI, CNNs (U-Net, ResNet), Vision Transformers, GANs, LSTMs, Custom Loss Design, Model Optimization
- 3D Graphics & Sim: Blender (Procedural Gen, Python API, Physics), Unity, Unreal Engine, Ray Tracing
- LLM & Agentic AI: Mistral AI API, Groq API, Gemini API, Prompt Engineering, LLM Integration, RAG, MCP (Model Context Protocol), Agentic Workflows, Claude Code
- Automation & DevOps: n8n, Docker, Linux, AWS, CI/CD, Vim, Shell Scripting, Automation Pipelines
- Software Engineering: Python (Expert), C++, C, TypeScript/JavaScript, Next.js, React Native, Node.js, Express.js, MongoDB, SQL, Git, ONNX
- Data Science: NumPy, Pandas, Scikit-learn, Matplotlib, Seaborn, Jupyter

RULES:
- NEVER fabricate experience — only reframe and reorder existing achievements
- Reorder experiences and projects by relevance to THIS job (most relevant first)
- Pick 2-3 experiences and 2-3 projects MAX — omit the rest to keep the resume to one page
- Reword bullet points to emphasize aspects relevant to the job (3-4 bullets per experience, 2-3 per project)
- Reorder skills categories and items within them by relevance; omit irrelevant categories
- Incorporate ATS keywords naturally into bullet points

Respond ONLY with valid JSON:
{"company": "<company>", "role": "<title>", "ats_keywords": ["..."], "experiences": [{"title": "...", "dates": "...", "company": "...", "location": "...", "bullets": ["..."]}], "projects": [{"name": "...", "tech": "...", "dates": "...", "bullets": ["..."]}], "skills": [{"category": "...", "items": "..."}]}`;

  const messages = [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ];

  // Try Groq first, fall back to Gemini 2.5 Flash Lite
  async function callGroq(ctx) {
    const body = { model: MODEL, messages, temperature: 0.3, response_format: { type: 'json_object' } };
    const retryDelays = [5000, 15000];
    for (let attempt = 0; attempt <= 2; attempt++) {
      try {
        const resp = await ctx.helpers.httpRequest({
          method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
          body, json: true,
          headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` }
        });
        return resp.choices?.[0]?.message?.content;
      } catch(e) {
        if (e.message?.includes('429') && attempt < 2) { await new Promise(r => setTimeout(r, retryDelays[attempt])); continue; }
        throw e;
      }
    }
  }

  async function callGemini(ctx) {
    const geminiKey = $env.GEMINI_API_KEY;
    if (!geminiKey) throw new Error('No GEMINI_API_KEY for fallback');
    const body = {
      contents: [{ parts: [{ text: systemPrompt + '\n\n' + userPrompt }] }],
      generationConfig: { temperature: 0.3, responseMimeType: 'application/json' }
    };
    const resp = await ctx.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite-preview-06-17:generateContent?key=${geminiKey}`,
      body, json: true, headers: { 'Content-Type': 'application/json' }
    });
    return resp.candidates?.[0]?.content?.parts?.[0]?.text;
  }

  let text;
  try {
    text = await callGroq.call(this, this);
  } catch(groqErr) {
    console.log('Groq failed (' + groqErr.message + '), falling back to Gemini 2.5 Flash Lite');
    text = await callGemini.call(this, this);
  }
  if (!text) throw new Error('No response from any LLM');
  const tailored = JSON.parse(text);
  return { json: { ...job, tailored_resume: tailored } };
}

const results = [];
for (let i = 0; i < items.length; i++) {
  const result = await tailorJob.call(this, items[i]);
  results.push(result);
}
return results;

// Call the PDF microservice to generate the tailored resume PDF
const job = $input.item.json;
const tailored = job.tailored_resume;

if (!tailored) throw new Error('No tailored_resume data found');

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://pdf-service:3456/',
  body: JSON.stringify(tailored),
  headers: { 'Content-Type': 'application/json' },
  encoding: 'arraybuffer',
  returnFullResponse: true
});

const headers = response.headers || {};
const filename = headers['x-filename'] || `Riad_Boussoura_CV_${(job.company || 'Company').replace(/[^\w-]/g, '_')}.pdf`;
const pdfBuffer = Buffer.isBuffer(response.body) ? response.body : Buffer.from(response.body);

return {
  json: {
    ...job,
    pdf_filename: filename
  },
  binary: {
    data: await this.helpers.prepareBinaryData(pdfBuffer, filename, 'application/pdf')
  }
};

// Prepare simplified row for Google Sheet
const drive = $input.item.json;
const driveId = drive.id || drive.fileId || '';

let job = {};
try {
  job = $('Generate PDF').item.json;
} catch(e) {
  try {
    const allPdfItems = $('Generate PDF').all();
    job = allPdfItems[$itemIndex]?.json || allPdfItems[0]?.json || {};
  } catch(e2) {
