  }
};

// Aggregate all processed jobs into one summary email
const items = $('Prepare Sheet Row').all();
if (items.length === 0) return [];

const date = new Date().toLocaleDateString('fr-FR');

function formatPostedDate(raw) {
  if (!raw) return '-';
  // Handle relative strings like "3 days ago" or "Mar 28" from SerpAPI
  if (isNaN(Date.parse(raw))) return raw;
  const d = new Date(raw);
  return d.toLocaleDateString('fr-FR') + ' ' + d.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
}

const rows = items.map(item => {
  const d = item.json;
  return `<tr>
    <td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Company']}</td>
    <td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Role']}</td>
    <td style="padding:6px 10px;border-bottom:1px solid #eee">${d['Location']}</td>
    <td style="padding:6px 10px;border-bottom:1px solid #eee">${formatPostedDate(d['Date Posted'])}</td>
    <td style="padding:6px 10px;border-bottom:1px solid #eee"><a href="${d['Apply URL']}">Apply</a></td>
    <td style="padding:6px 10px;border-bottom:1px solid #eee"><a href="${d['Resume PDF']}">CV</a></td>
  </tr>`;
}).join('
');

return [{
  json: {
    emailSubject: `Job Pipeline: ${items.length} new jobs (${date})`,
    emailBody: `<div style="font-family:Arial,sans-serif;max-width:800px">
<h2 style="color:#333">Job Pipeline Run Summary</h2>
<p><strong>${items.length}</strong> new jobs found and tailored resumes generated.</p>
<table style="border-collapse:collapse;width:100%;font-size:14px">
  <tr style="background:#2d5016;color:white">
    <th style="padding:8px 10px;text-align:left">Company</th>
    <th style="padding:8px 10px;text-align:left">Role</th>
    <th style="padding:8px 10px;text-align:left">Location</th>
    <th style="padding:8px 10px;text-align:left">Posted</th>
    <th style="padding:8px 10px;text-align:left">Apply</th>
    <th style="padding:8px 10px;text-align:left">Resume</th>
  </tr>
  ${rows}
</table>
<br>
<p style="color:#888;font-size:12px">Sent by your Job Search Automation Pipeline</p>
</div>`
  }
}];

// France Travail (Pole Emploi) — Official French job board
// Register at https://francetravail.io for client credentials
const clientId = $env.FRANCE_TRAVAIL_CLIENT_ID;
const clientSecret = $env.FRANCE_TRAVAIL_CLIENT_SECRET;

if (!clientId || !clientSecret) {
  console.log('[FranceTravail] No credentials, skipping');
  return [{ json: { results: [], count: 0 } }];
}

// Get OAuth2 token
let token;
try {
  const authResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://entreprise.francetravail.fr/connexion/oauth2/access_token?realm=/partenaire',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=client_credentials&client_id=${encodeURIComponent(clientId)}&client_secret=${encodeURIComponent(clientSecret)}&scope=api_offresdemploiv2%20o2dsoffre`,
  });
  const parsed = typeof authResp === 'string' ? JSON.parse(authResp) : authResp;
  token = parsed.access_token;
} catch(e) {
  console.log('[FranceTravail] Auth failed: ' + e.message);
  return [{ json: { results: [], count: 0 } }];
}

const queries = [
  'computer vision',
  'machine learning',
  'deep learning',
  'ingenieur logiciel'
];

const allResults = [];
for (const q of queries) {
  try {
    const url = `https://api.francetravail.io/partenaire/offresdemploi/v2/offres/search?motsCles=${encodeURIComponent(q)}&range=0-24&publieeDepuis=3`;
    const resp = await this.helpers.httpRequest({
      method: 'GET', url,
      headers: { 'Authorization': `Bearer ${token}` },
      json: true
    });
    if (resp.resultats) allResults.push(...resp.resultats);
  } catch(e) { /* skip */ }
}

return [{ json: { results: allResults, count: allResults.length } }];

// Remotive — Free remote tech jobs API (no auth needed)
const categories = ['software-dev', 'data'];
const allJobs = [];
const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000; // last 7 days

for (const cat of categories) {
  try {
    const url = `https://remotive.com/api/remote-jobs?category=${cat}&limit=50`;
    const resp = await this.helpers.httpRequest({ method: 'GET', url, json: true });
    if (resp.jobs) {
      const recent = resp.jobs.filter(j => new Date(j.publication_date).getTime() >= cutoff);
      allJobs.push(...recent);
    }
  } catch(e) { /* skip */ }
}

return [{ json: { jobs: allJobs, count: allJobs.length } }];

// Arbeitnow — Free EU tech jobs API (no auth needed)
// Keyword filter: keep only jobs matching our target domains
const KEYWORDS = [
  'python', 'machine learning', 'deep learning', 'computer vision',
  'artificial intelligence', ' ai ', 'pytorch', 'tensorflow', 'opencv',
  'software engineer', 'software developer', 'backend', 'fullstack',
  'full-stack', 'full stack', '3d', 'rendering', 'unity', 'unreal',
  'blender', 'graphics', 'vision', 'image processing', 'mlops',
  'data scientist', 'data engineer', 'neural network', 'nlp',
  'r&d engineer', 'research engineer', 'algorithm'
];

try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.arbeitnow.com/api/job-board-api',
    json: true
  });
  const cutoff = Math.floor(Date.now() / 1000) - 3 * 24 * 60 * 60;
  const recent = (resp.data || []).filter(j => {
    if (j.created_at < cutoff) return false;
    const text = `${j.title || ''} ${j.description || ''} ${(j.tags || []).join(' ')}`.toLowerCase();
    return KEYWORDS.some(kw => text.includes(kw));
  });
  return [{ json: { data: recent, count: recent.length } }];
} catch(e) {
  return [{ json: { data: [], count: 0 } }];
}

// JSearch (RapidAPI) — Aggregates LinkedIn, Indeed, Glassdoor
// Free tier: 500 req/month. Register at rapidapi.com
const apiKey = $env.RAPIDAPI_KEY;

if (!apiKey) {
  console.log('[JSearch] No RAPIDAPI_KEY set, skipping');
  return [{ json: { data: [], count: 0 } }];
}

const queries = [
  'computer vision engineer in France',
  'machine learning python developer in France'
];

const allJobs = [];
for (const q of queries) {
  try {
    const url = `https://jsearch.p.rapidapi.com/search?query=${encodeURIComponent(q)}&page=1&num_pages=1&date_posted=3days`;
    const resp = await this.helpers.httpRequest({
      method: 'GET', url,
      headers: {
        'X-RapidAPI-Key': apiKey,
        'X-RapidAPI-Host': 'jsearch.p.rapidapi.com'
      },
      json: true
    });
    if (resp.data) allJobs.push(...resp.data);
  } catch(e) { /* skip */ }
}

return [{ json: { data: allJobs, count: allJobs.length } }];
